</a>
<p>
  Adjust the size of the `ToggleButton` using the `size` prop. Supported values include `small`, `medium`, and `large`.
</p>

<div className="showcase">
  <div className="items">
    <ThemeWrapper>
      <SizesDemo />
    </ThemeWrapper>
  </div>
  <CodeBlock name="tb-sizes" collapsible code={codes[2]} />
</div>

